const API = window.location.origin;

const api = {
  async readClipboard() {
    try { const r = await fetch(`${API}/api/clipboard`); return (await r.json()).text || ''; } catch { return ''; }
  },
  async openFolder(path) { await fetch(`${API}/api/open-folder`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({path})}); },
  async info(url) { return (await fetch(`${API}/api/info`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({url})})).json(); },
  async download(opts) { return (await fetch(`${API}/api/download`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(opts)})).json(); },
  async cancel() { await fetch(`${API}/api/cancel`,{method:'POST'}); },
  async getConfig() { return (await fetch(`${API}/api/config`)).json(); },
  async saveConfig(c) { await fetch(`${API}/api/config`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(c)}); },
  async getHistory() { return (await fetch(`${API}/api/history`)).json(); },
  async deleteHistory(b) { return (await fetch(`${API}/api/history`,{method:'DELETE',headers:{'Content-Type':'application/json'},body:JSON.stringify(b)})).json(); },
  async getLibrary() { return (await fetch(`${API}/api/library`)).json(); },
  async addLibrary(e) { return (await fetch(`${API}/api/library`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(e)})).json(); },
  async updateLibEntry(id,e) { return (await fetch(`${API}/api/library/${id}`,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify(e)})).json(); },
  async deleteLibEntry(id) { return (await fetch(`${API}/api/library/${id}`,{method:'DELETE'})).json(); },
  async syncPlaylist(id,mode) { return (await fetch(`${API}/api/library/${id}/sync`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({mode})})).json(); },
  async checkUpdate() { return (await fetch(`${API}/api/check-ytdlp-update`)).json(); },
  async doUpdate() { return (await fetch(`${API}/api/update-ytdlp`,{method:'POST'})).json(); },
  async getSystem() { return (await fetch(`${API}/api/system`)).json(); },
  subscribeProgress(cb) {
    const es = new EventSource(`${API}/api/progress`);
    es.onmessage = e => cb(JSON.parse(e.data));
    return () => es.close();
  }
};

function detectUrlType(url) {
  if (!url) return null;
  const u = url.toLowerCase();
  if (u.includes('playlist?list=') || u.includes('/sets/') || u.includes('/album/') || u.includes('/playlist/') || u.includes('youtube.com/@') || u.includes('youtube.com/channel/')) return 'playlist';
  return 'video';
}

